Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var savedPaths = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var savePath = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(savePath);
        await file.CopyToAsync(stream);
        savedPaths.Add(savePath);
    }

    return Results.Ok(new
    {
        Description = description,
        FileCount = savedPaths.Count,
        Paths = savedPaths
    });
})
.DisableAntiforgery()                          // required for minimal APIs accepting forms
.Accepts<IFormFile>("multipart/form-data")
.Produces(200)
.Produces(400);

app.Run();
```

**Key points:**

- **`ConfigureKestrel`** — raises the default 30 MB body limit to 50 MB.
- **`ReadFormAsync`** — parses the multipart body; files come from `form.Files`, text fields from `form["key"]`.
- **`DisableAntiforgery()`** — without this, .NET 8 minimal APIs reject form POSTs by default.
- **Content-type check** — basic guard so only `image/*` files are accepted.

**Test with `curl`:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```

If you'd rather bind to a typed model instead of reading `HttpRequest` directly, use `[FromForm]`:

```csharp
app.MapPost("/upload-typed", async ([FromForm] UploadRequest req) => { /* ... */ });

public class UploadRequest
{
    public string Description { get; set; } = "";
    public IFormFileCollection Images { get; set; } = default!;
}
```
